import{_ as e,o as d,c as a,ag as o}from"./chunks/framework.OsDJF_Ea.js";const p=JSON.parse('{"title":"Local Analysis","description":"","frontmatter":{},"headers":[],"relativePath":"local-analysis.md","filePath":"local-analysis.md"}'),r={name:"local-analysis.md"};function i(n,t,c,s,l,h){return d(),a("div",null,[...t[0]||(t[0]=[o('<h1 id="local-analysis" tabindex="-1">Local Analysis <a class="header-anchor" href="#local-analysis" aria-label="Permalink to &quot;Local Analysis&quot;">​</a></h1><p>CatalystOps runs 40+ anti-pattern checks on every Python file open and save — no cluster, no network call, no configuration required.</p><h2 id="how-it-works" tabindex="-1">How It Works <a class="header-anchor" href="#how-it-works" aria-label="Permalink to &quot;How It Works&quot;">​</a></h2><p>When you open or edit a <code>.py</code> file, CatalystOps:</p><ol><li>Scans the code with regex-based pattern matchers</li><li>Flags issues inline as VS Code diagnostics (squiggly underlines)</li><li>Shows a hover card with a one-sentence explanation and a quick-fix snippet</li><li>Updates the <strong>Issues</strong> sidebar with a full list</li></ol><p>Analysis also runs on Jupyter notebooks (<code>.ipynb</code>) — each cell is analyzed in context and issues are mapped back to the correct cell.</p><h2 id="severity-levels" tabindex="-1">Severity Levels <a class="header-anchor" href="#severity-levels" aria-label="Permalink to &quot;Severity Levels&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Level</th><th>Color</th><th>Meaning</th></tr></thead><tbody><tr><td><strong>Critical</strong></td><td>Red</td><td>Will likely cause OOM, data loss, or incorrect results</td></tr><tr><td><strong>Warning</strong></td><td>Yellow</td><td>Performance problem that will hurt at scale</td></tr><tr><td><strong>Info</strong></td><td>Blue</td><td>Best-practice recommendation</td></tr><tr><td><strong>Suggestion</strong></td><td>Grey</td><td>Minor improvement opportunity</td></tr></tbody></table><h2 id="suppressing-a-rule" tabindex="-1">Suppressing a Rule <a class="header-anchor" href="#suppressing-a-rule" aria-label="Permalink to &quot;Suppressing a Rule&quot;">​</a></h2><p>Add <code># noqa: catalystops</code> to any line to suppress all rules on that line:</p><div class="language-python vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">python</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">df.collect()  </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># noqa: catalystops</span></span></code></pre></div><h2 id="rule-categories" tabindex="-1">Rule Categories <a class="header-anchor" href="#rule-categories" aria-label="Permalink to &quot;Rule Categories&quot;">​</a></h2><h3 id="spark-actions" tabindex="-1">Spark Actions <a class="header-anchor" href="#spark-actions" aria-label="Permalink to &quot;Spark Actions&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Rule ID</th><th>Severity</th><th>Description</th></tr></thead><tbody><tr><td><code>CODE_COLLECT_001</code></td><td>Critical</td><td><code>collect()</code> pulls all data to the driver — OOM risk on large datasets</td></tr><tr><td><code>CODE_PANDAS_001</code></td><td>Warning</td><td><code>toPandas()</code> brings all data to the driver</td></tr><tr><td><code>CODE_COUNT_001</code></td><td>Warning</td><td><code>count() &gt; 0</code> triggers a full Spark job; use <code>isEmpty()</code> instead</td></tr><tr><td><code>CODE_ITER_COLLECT_001</code></td><td>Critical</td><td><code>for row in df.collect()</code> iterates row-by-row on the driver</td></tr></tbody></table><h3 id="joins" tabindex="-1">Joins <a class="header-anchor" href="#joins" aria-label="Permalink to &quot;Joins&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Rule ID</th><th>Severity</th><th>Description</th></tr></thead><tbody><tr><td><code>CODE_CROSSJOIN_001</code></td><td>Critical</td><td><code>crossJoin()</code> or implicit cartesian product</td></tr><tr><td><code>CODE_COALESCE_001</code></td><td>Warning</td><td><code>coalesce(1)</code> funnels all data to one partition</td></tr></tbody></table><h3 id="shuffles-partitioning" tabindex="-1">Shuffles &amp; Partitioning <a class="header-anchor" href="#shuffles-partitioning" aria-label="Permalink to &quot;Shuffles &amp; Partitioning&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Rule ID</th><th>Severity</th><th>Description</th></tr></thead><tbody><tr><td><code>CODE_ORDERBY_001</code></td><td>Warning</td><td>Global <code>orderBy()</code> / <code>sort()</code> triggers a full shuffle</td></tr><tr><td><code>CODE_REPARTITION_001</code></td><td>Warning</td><td><code>repartition(N)</code> before a write — use <code>coalesce()</code> to avoid the full shuffle</td></tr><tr><td><code>CODE_WINDOW_001</code></td><td>Warning</td><td><code>Window.orderBy()</code> without <code>partitionBy()</code> — global window, single partition</td></tr></tbody></table><h3 id="dataframe-operations" tabindex="-1">DataFrame Operations <a class="header-anchor" href="#dataframe-operations" aria-label="Permalink to &quot;DataFrame Operations&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Rule ID</th><th>Severity</th><th>Description</th></tr></thead><tbody><tr><td><code>CODE_WITHCOLUMN_LOOP_001</code></td><td>Warning</td><td><code>withColumn()</code> inside a loop creates a new plan node per iteration</td></tr><tr><td><code>CODE_REPEATED_ACTIONS_001</code></td><td>Warning</td><td>Multiple actions on the same DataFrame without <code>.cache()</code></td></tr><tr><td><code>CODE_REPRO_001</code></td><td>Info</td><td>Repeated source scan without <code>.cache()</code> or <code>.persist()</code></td></tr></tbody></table><h3 id="udfs" tabindex="-1">UDFs <a class="header-anchor" href="#udfs" aria-label="Permalink to &quot;UDFs&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Rule ID</th><th>Severity</th><th>Description</th></tr></thead><tbody><tr><td><code>CODE_UDF_001</code></td><td>Info</td><td>Python UDF prevents query plan optimization</td></tr><tr><td><code>CODE_UDF_FILTER_001</code></td><td>Warning</td><td>UDF inside <code>.filter()</code> blocks predicate pushdown on Delta/partitioned tables</td></tr></tbody></table><h3 id="schema-reads" tabindex="-1">Schema &amp; Reads <a class="header-anchor" href="#schema-reads" aria-label="Permalink to &quot;Schema &amp; Reads&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Rule ID</th><th>Severity</th><th>Description</th></tr></thead><tbody><tr><td><code>CODE_SCHEMA_001</code></td><td>Info</td><td><code>inferSchema=true</code> requires an extra data pass; provide an explicit schema</td></tr><tr><td><code>CODE_SELECT_STAR_001</code></td><td>Info</td><td><code>SELECT *</code> may read unnecessary columns</td></tr><tr><td><code>CODE_WRITE_MODE_001</code></td><td>Info</td><td>Missing <code>.mode()</code> on write — defaults to <code>error</code>, will fail if data exists</td></tr></tbody></table><h3 id="security" tabindex="-1">Security <a class="header-anchor" href="#security" aria-label="Permalink to &quot;Security&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Rule ID</th><th>Severity</th><th>Description</th></tr></thead><tbody><tr><td><code>CODE_SQL_INJECT_001</code></td><td>Critical</td><td>f-string interpolation in <code>spark.sql()</code> — SQL injection risk</td></tr><tr><td><code>CODE_KAFKA_COMMIT_001</code></td><td>Critical</td><td>Kafka auto-commit enabled — can cause data loss or duplication</td></tr></tbody></table><h3 id="streaming" tabindex="-1">Streaming <a class="header-anchor" href="#streaming" aria-label="Permalink to &quot;Streaming&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Rule ID</th><th>Severity</th><th>Description</th></tr></thead><tbody><tr><td><code>CODE_STREAMING_TRIGGER_001</code></td><td>Warning</td><td>No <code>.trigger()</code> — runs continuous micro-batches</td></tr><tr><td><code>CODE_STREAMING_WATERMARK_001</code></td><td>Warning</td><td><code>groupBy()</code> without watermark causes unbounded state accumulation</td></tr><tr><td><code>CODE_STREAMING_INNER_JOIN_001</code></td><td>Warning</td><td>Streaming inner join silently drops late events</td></tr><tr><td><code>CODE_DYNAMIC_ALLOC_001</code></td><td>Warning</td><td>Dynamic allocation on a streaming cluster causes instability</td></tr><tr><td><code>CODE_ROCKSDB_001</code></td><td>Info</td><td>Stateful streaming without RocksDB state store</td></tr><tr><td><code>CODE_AUTOLOADER_RATE_001</code></td><td>Warning</td><td>Auto Loader without <code>maxBytesPerTrigger</code> — unbounded ingestion rate</td></tr><tr><td><code>CODE_CHECKPOINT_DBFS_001</code></td><td>Warning</td><td>Checkpoint stored on DBFS — use cloud storage for reliability</td></tr><tr><td><code>CODE_UNNAMED_QUERY_001</code></td><td>Info</td><td>Streaming query has no name — harder to monitor</td></tr></tbody></table><h3 id="delta-lake" tabindex="-1">Delta Lake <a class="header-anchor" href="#delta-lake" aria-label="Permalink to &quot;Delta Lake&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Rule ID</th><th>Severity</th><th>Description</th></tr></thead><tbody><tr><td><code>CODE_MERGE_DV_001</code></td><td>Info</td><td>MERGE without Deletion Vectors enabled</td></tr><tr><td><code>CODE_MERGE_RLC_001</code></td><td>Info</td><td>MERGE without Row-Level Concurrency</td></tr><tr><td><code>CODE_OPTIMIZE_MERGE_001</code></td><td>Warning</td><td><code>OPTIMIZE</code> after every MERGE causes latency spikes</td></tr><tr><td><code>CODE_DROP_CREATE_001</code></td><td>Warning</td><td><code>DROP TABLE</code> + <code>CREATE TABLE</code> is non-atomic; use <code>CREATE OR REPLACE</code></td></tr><tr><td><code>CODE_ZORDER_001</code></td><td>Info</td><td>ZORDER is deprecated for new tables; use Liquid Clustering</td></tr><tr><td><code>CODE_ANALYZE_001</code></td><td>Info</td><td>Missing <code>ANALYZE TABLE</code> after large writes — statistics may be stale</td></tr><tr><td><code>CODE_FLOAT_FINANCIAL_001</code></td><td>Warning</td><td>FLOAT/DOUBLE for financial columns loses precision; use DECIMAL</td></tr></tbody></table><h3 id="dlt-pipelines" tabindex="-1">DLT Pipelines <a class="header-anchor" href="#dlt-pipelines" aria-label="Permalink to &quot;DLT Pipelines&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Rule ID</th><th>Severity</th><th>Description</th></tr></thead><tbody><tr><td><code>CODE_DLT_PARTITION_001</code></td><td>Info</td><td>DLT <code>PARTITIONED BY</code> / <code>partition_cols</code> — prefer Liquid Clustering</td></tr><tr><td><code>CODE_DLT_CDC_ORDER_001</code></td><td>Critical</td><td><code>APPLY AS DELETE WHEN</code> in wrong clause order causes incorrect CDC</td></tr><tr><td><code>CODE_READ_FILES_SCHEMA_001</code></td><td>Info</td><td><code>read_files()</code> without <code>schemaHints</code> — schema inference on every run</td></tr></tbody></table>',32)])])}const _=e(r,[["render",i]]);export{p as __pageData,_ as default};
